        ["mentor.main.about"] = ("About", "Giới thiệu"),
        ["mentor.main.bio1"] = ("Th.S. Nguyễn Thuỵ Tố Trâm is the Lead Mentor of SoftSync Space, accompanying the team throughout its research, design, and platform development. As a Soft Skills Lecturer at FPT University – Can Tho Campus, she provides professional guidance on skill development, user experience, and human-centered learning models.", "Th.S. Nguyễn Thuỵ Tố Trâm là Mentor chính của dự án SoftSync Space, đồng hành cùng nhóm trong quá trình nghiên cứu, xây dựng và phát triển nền tảng. Với vai trò là Giảng viên Bộ môn Kỹ năng mềm tại Trường Đại học FPT – Phân hiệu Cần Thơ, cô mang đến những định hướng chuyên môn về phát triển kỹ năng, trải nghiệm người dùng và xây dựng mô hình học tập lấy con người làm trung tâm."),
        ["mentor.main.bio2"] = ("Her practical experience in social work, disability inclusion, and soft skills helps SoftSync Space develop according to Universal Design principles, ensuring that the platform not only applies AI effectively but also creates a safe, equitable, and welcoming learning environment for every user.", "Những kinh nghiệm thực của cô trong lĩnh vực công tác xã hội, hòa nhập khuyết tật và kỹ năng mềm giúp SoftSync Space định hướng phát triển theo tiêu chí tiếp cận toàn diện (Universal Design), đảm bảo nền tảng không chỉ ứng dụng công nghệ AI hiệu quả mà còn tạo ra một môi trường học tập an toàn, bình đẳng và thân thiện với mọi người dùng."),
        ["mentor.main.bio3"] = ("Her partnership is an important foundation that helps SoftSync Space balance educational value, technology, and social responsibility while building a modern and sustainable soft-skills ecosystem for young people.", "Sự đồng hành của cô là nền tảng quan trọng giúp SoftSync Space cân bằng giữa giá trị giáo dục, yếu tố công nghệ và trách nhiệm xã hội, hướng tới xây dựng một hệ sinh thái phát triển kỹ năng mềm hiện đại và bền vững cho thế hệ trẻ."),
        ["mentor.main.specialty.softSkills"] = ("Soft skills", "Kỹ năng mềm"),
        ["mentor.main.specialty.community"] = ("Social work", "Công tác xã hội"),
        ["mentor.main.specialty.inclusion"] = ("Disability inclusion", "Hòa nhập khuyết tật"),
        ["mentor.advisor.role"] = ("Professional Advisor", "Cố vấn Chuyên môn"),
        ["mentor.advisor.position"] = ("Soft Skills Lecturer – FPT Polytechnic College, Can Tho", "Giảng viên Kỹ năng mềm – Trường Cao đẳng FPT Polytechnic Cần Thơ"),
        ["mentor.advisor.summary"] = ("Master of Psychology and advisor in applied psychology, soft-skills development, training content, and user experience for SoftSync Space.", "Thạc sĩ Tâm lý học, cố vấn về tâm lý học ứng dụng, phát triển kỹ năng mềm, nội dung đào tạo và trải nghiệm người dùng cho SoftSync Space."),
        ["mentor.advisor.highlight1"] = ("Master's degree in Psychology", "Thạc sĩ Tâm lý học"),
        ["mentor.advisor.highlight2"] = ("Soft Skills Lecturer at FPT Polytechnic College, Can Tho", "Giảng viên Kỹ năng mềm – Trường Cao đẳng FPT Polytechnic Cần Thơ"),
        ["mentor.advisor.highlight3"] = ("Expertise in applied psychology and soft-skills development for students", "Chuyên môn về tâm lý học ứng dụng và phát triển kỹ năng mềm cho học sinh, sinh viên"),
        ["mentor.advisor.highlight4"] = ("Guidance in personal development, communication skills, and mental well-being", "Đồng hành trong việc định hướng phát triển cá nhân, kỹ năng giao tiếp và sức khỏe tinh thần"),
        ["mentor.advisor.highlight5"] = ("Professional advisor for training content and user experience at SoftSync Space", "Cố vấn chuyên môn về nội dung đào tạo và trải nghiệm người dùng của dự án SoftSync Space"),
        ["mentor.advisor.bio"] = ("Th.S. Nguyễn Hoàng Vân Anh joins SoftSync Space as a Professional Advisor, bringing a strong foundation in psychology and experience in soft-skills education for students. With expertise in applied psychology, she supports the team in developing content suited to learners' psychological needs, skill-assessment features, personalized development pathways, and a better user experience. Her guidance helps SoftSync Space grow through a scientific, human-centered approach and foster a positive, safe, and meaningful learning environment for young people.", "Th.S. Nguyễn Hoàng Vân Anh đồng hành cùng SoftSync Space với vai trò Cố vấn Chuyên môn, mang đến nền tảng kiến thức về tâm lý học và kinh nghiệm đào tạo kỹ năng mềm cho học sinh, sinh viên. Với chuyên môn trong lĩnh vực tâm lý học ứng dụng, cô hỗ trợ nhóm xây dựng nội dung phù hợp với đặc điểm tâm lý của người học, góp phần phát triển các tính năng đánh giá kỹ năng, định hướng lộ trình cá nhân hóa và nâng cao trải nghiệm người dùng. Sự đồng hành của cô giúp SoftSync Space phát triển theo hướng khoa học, lấy con người làm trung tâm và tạo ra một môi trường học tập tích cực, an toàn và giàu giá trị cho cộng đồng người trẻ."),
        ["mentor.advisor.specialty.psychology"] = ("Applied psychology", "Tâm lý học ứng dụng"),
        ["mentor.advisor.specialty.development"] = ("Personal development", "Phát triển cá nhân"),
        ["mentor.advisor.xuan.position"] = ("Soft Skills Lecturer – FPT Polytechnic College, Vinh Phuc Campus", "Giảng viên Bộ môn Kỹ năng mềm – Trường Cao đẳng FPT Polytechnic, cơ sở Vĩnh Phúc"),
        ["mentor.advisor.xuan.summary"] = ("Educator with more than 17 years of experience, advising SoftSync Space on soft-skills development, educational technology, and practical learning pathways.", "Nhà giáo với hơn 17 năm kinh nghiệm, cố vấn cho SoftSync Space về phát triển kỹ năng mềm, ứng dụng công nghệ trong giáo dục và xây dựng lộ trình thực tiễn cho người học."),
        ["mentor.advisor.xuan.highlight1"] = ("Soft Skills Lecturer at FPT Polytechnic College, Vinh Phuc Campus", "Giảng viên Bộ môn Kỹ năng mềm – Trường Cao đẳng FPT Polytechnic, cơ sở Vĩnh Phúc"),
        ["mentor.advisor.xuan.highlight2"] = ("Educator with more than 17 years of experience", "Nhà giáo với hơn 17 năm kinh nghiệm"),
        ["mentor.advisor.xuan.highlight3"] = ("Supports students throughout their skills-development and personal-growth journeys", "Đồng hành cùng học sinh, sinh viên trên hành trình phát triển kỹ năng và hoàn thiện bản thân"),
        ["mentor.advisor.xuan.highlight4"] = ("Professional advisor in soft-skills development and the application of technology in education", "Cố vấn chuyên môn về phát triển kỹ năng mềm và ứng dụng công nghệ trong giáo dục"),
        ["mentor.advisor.xuan.highlight5"] = ("Guides content, development pathways, and the practical value of SoftSync Space", "Hỗ trợ định hướng nội dung, xây dựng lộ trình phát triển và nâng cao giá trị thực tiễn của dự án SoftSync Space"),
        ["mentor.advisor.xuan.bio"] = ("With more than 17 years of experience in education and soft-skills training, Th.S. Nguyễn Xuân joins SoftSync Space as a Professional Advisor, supporting strategic direction, specialist content development, and the platform's practical relevance. Drawing on her experience teaching and training generations of students, she brings valuable perspectives on soft-skills development while advising on the effective, humane, and learner-centered use of technology and AI in education. Her guidance helps SoftSync Space become a modern, high-quality, community-focused soft-skills development platform.", "Với hơn 17 năm kinh nghiệm trong lĩnh vực giáo dục và đào tạo kỹ năng mềm, Th.S. Nguyễn Xuân đồng hành cùng SoftSync Space với vai trò Cố vấn Chuyên môn, hỗ trợ định hướng chiến lược phát triển, xây dựng nội dung chuyên môn và đảm bảo tính thực tiễn của nền tảng. Bằng kinh nghiệm giảng dạy và đào tạo nhiều thế hệ học sinh, sinh viên, cô mang đến những góc nhìn giá trị trong việc phát triển kỹ năng mềm, đồng thời tư vấn định hướng ứng dụng công nghệ và AI vào giáo dục theo hướng hiệu quả, nhân văn và phù hợp với nhu cầu của người học. Sự đồng hành của cô góp phần giúp SoftSync Space trở thành một nền tảng phát triển kỹ năng mềm hiện đại, chất lượng và hướng đến cộng đồng."),
        ["mentor.advisor.xuan.specialty.experience"] = ("17+ years of experience", "17+ năm kinh nghiệm"),
        ["mentor.advisor.xuan.specialty.edtech"] = ("Educational technology", "Công nghệ giáo dục"),
