        ["assistant.title"] = ("AI Assistant", "Trợ lý AI"),
        ["assistant.subtitle"] = ("Ask me anything about soft skills or your progress.", "Hỏi tôi bất cứ điều gì về kỹ năng mềm hoặc tiến độ của bạn."),
