        ["assistant.exploreLessons"] = ("Explore lessons", "Khám phá bài học"), ["assistant.trackProgress"] = ("Track progress", "Theo dõi tiến độ"),
        ["assistant.joinCommunity"] = ("Join community", "Tham gia cộng đồng"), ["assistant.sideQuote"] = ("Soft skills today, success tomorrow.", "Kỹ năng hôm nay, thành công ngày mai."),
