        ["assistant.prompt.practice"] = ("Practice a skill", "Luyện tập kỹ năng"), ["assistant.prompt.practiceSub"] = ("Give me a real-world scenario", "Cho mình một tình huống thực tế"),
        ["assistant.prompt.advice"] = ("Get advice", "Nhận lời khuyên"), ["assistant.prompt.adviceSub"] = ("Tips to improve my soft skills", "Mẹo cải thiện kỹ năng mềm"),
        ["assistant.prompt.progress"] = ("Track progress", "Theo dõi tiến độ"), ["assistant.prompt.progressSub"] = ("Review my learning journey", "Xem lại hành trình học tập"),
        ["assistant.prompt.lessonText"] = ("Please explain a soft-skills lesson step by step.", "Hãy giải thích một bài học kỹ năng mềm theo từng bước."),
        ["assistant.prompt.practiceText"] = ("Give me a real-world scenario to practice.", "Hãy cho mình một tình huống thực tế để luyện tập."),
        ["assistant.prompt.adviceText"] = ("Give me advice to improve my soft skills.", "Hãy cho mình lời khuyên để cải thiện kỹ năng mềm."),
        ["assistant.welcome"] = ("👋 Hello! I'm your SoftSync learning assistant.\n\nAsk me about lessons, soft skills, real-world scenarios, or anything you are practicing. I'll explain and guide you step by step.\n\nWhat would you like to learn today?", "👋 Xin chào! Mình là Trợ lý học tập của SoftSync.\n\nBạn có thể hỏi mình về bài học, kỹ năng mềm, tình huống thực tế hoặc nội dung đang luyện tập. Mình sẽ giải thích và hướng dẫn từng bước.\n\nHôm nay bạn muốn học gì?"),
        ["chatbot.tagline"] = ("Your learning companion", "Người bạn đồng hành của bạn"),
        ["chatbot.welcome.title"] = ("Hello, I'm SYNCY AI!", "Xin chào, mình là SYNCY AI!"),
        ["chatbot.welcome.desc"] = ("Welcome to SoftSync Space. I can help you explore the platform and choose the right place to begin.", "Chào mừng bạn đến với SoftSync Space. Mình có thể giúp bạn khám phá nền tảng và chọn điểm bắt đầu phù hợp."),
        ["chatbot.about.title"] = ("What is SoftSync Space?", "SoftSync Space là gì?"),
        ["chatbot.about.desc"] = ("SoftSync is an AI platform for developing soft skills through assessments, personalized roadmaps, simulations, and a learning community.", "SoftSync là nền tảng AI giúp người trẻ phát triển kỹ năng mềm qua đánh giá, lộ trình cá nhân hóa, tình huống mô phỏng và cộng đồng học tập."),
        ["chatbot.premium.title"] = ("Premium – 69,000 VND/month", "Premium – 69.000đ/tháng"),
        ["chatbot.premium.desc"] = ("Get specialized AI Mentors, deeper analysis, personalized roadmaps, advanced scenarios, and detailed progress tracking.", "Trải nghiệm AI Mentor chuyên biệt, phân tích chuyên sâu, lộ trình cá nhân hóa, tình huống nâng cao và thống kê tiến độ chi tiết."),
        ["chatbot.mentor.title"] = ("Mentors & Community", "Mentor và cộng đồng"),
        ["chatbot.mentor.desc"] = ("You can currently use AI Mentors and explore the community. Direct connections with Mentors and Experts are planned for future versions.", "Hiện tại bạn có thể sử dụng AI Mentor và khám phá cộng đồng. SoftSync hướng tới kết nối trực tiếp với Mentor và Expert trong các phiên bản tiếp theo."),
        ["chatbot.how.title"] = ("How does SoftSync work?", "SoftSync hoạt động thế nào?"),
        ["chatbot.how.desc"] = ("AI first assesses your skills. SYNCY then analyzes the results and recommends a roadmap, lessons, and practical scenarios while tracking progress over time.", "Đầu tiên, AI đánh giá kỹ năng của bạn. Sau đó SYNCY phân tích kết quả, gợi ý lộ trình và đề xuất bài học hoặc tình huống thực tế. Tiến độ sẽ được ghi nhận theo thời gian."),
        ["chatbot.action.assess"] = ("Skill assessment", "Đánh giá kỹ năng"), ["chatbot.action.roadmap"] = ("Suggested roadmap", "Gợi ý lộ trình"),
        ["chatbot.action.mentor"] = ("Explore Mentors", "Khám phá Mentor"), ["chatbot.action.progress"] = ("View progress", "Xem tiến độ"),
